module adder_pipe_64bit (
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output reg [64:0] result,
    output reg o_en
);

reg [63:0] adda_reg, addb_reg;
reg [64:0] sum_reg;
reg [4:0] pipeline_stage;
reg o_en_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        adda_reg <= 0;
        addb_reg <= 0;
        sum_reg <= 0;
        pipeline_stage <= 0;
        o_en_reg <= 0;
    end else begin
        if (i_en) begin
            adda_reg <= adda;
            addb_reg <= addb;
            sum_reg <= adda_reg + addb_reg;
            pipeline_stage <= 1;
            o_en_reg <= 1;
        end else begin
            pipeline_stage <= 0;
            o_en_reg <= 0;
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        result <= 0;
        o_en <= 0;
    end else begin
        if (pipeline_stage == 1) begin
            result <= {sum_reg[63], sum_reg};
            pipeline_stage <= 2;
        end else if (pipeline_stage == 2) begin
            result <= {sum_reg[63], sum_reg};
            pipeline_stage <= 3;
        end else if (pipeline_stage == 3) begin
            result <= {sum_reg[63], sum_reg};
            pipeline_stage <= 4;
        end else if (pipeline_stage == 4) begin
            result <= {sum_reg[63], sum_reg};
            pipeline_stage <= 5;
        end else if (pipeline_stage == 5) begin
            result <= {sum_reg[63], sum_reg};
            pipeline_stage <= 0;
        end
        o_en <= o_en_reg;
    end
end

endmodule
